Here's a minimal example of generating a method on the struct you parsed. This expands into code adding a new function to your type. For example:

```rust
let fields = &ast.data.as_ref().into_inner();
match fields {
    Data::Struct(fields) => {
        let expanded = quote! {
            impl #ast ident {
                pub fn hello(&self) -> usize { 42 }
            }
        };
        TokenStream::from(expanded)
    }
    _ => panic!("Unsupported data type!")
}
```
This way, you generate a new `hello` method inside the user's struct that always returns 42.

#![proc_macro_derive(SayHello)]

extern crate proc_macro;
use proc_macro::{TokenStream};

use syn;
use quote;

#[proc_macro_derive(SayHello)]
pub fn say_hello_derive(input: TokenStream) -> TokenStream {
    let ast = syn::parse2(input.clone()).unwrap();

    match &ast.data {
        syn::Data::Struct(data) => {
            let struct_name = &ast.ident;
            let method_body = quote! {
                pub fn say_hello(&self) {
                    println!("Hello, my name is {}!", stringify!(#struct_name));
                }
            };

            TokenStream::from(
                quote! {
                    #input
                    impl #struct_name {
                        #method_body
                    }
                }
            ).into()
        }
        _ => panic!("Can only derive for structs!")
    }
}

